import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []

all_keys = sorted(set(b.keys()) | set(a.keys()))
for k in all_keys:
    proj, fw, pkg = k
    bv = b.get(k)
    av = a.get(k)
    if bv and av and bv == av:
        unchanged.append((proj, fw, pkg, av))
    elif bv and av and bv != av:
        changes.append((proj, fw, pkg, bv, av, 'Aligned to highest version'))
    elif bv and not av:
        changes.append((proj, fw, pkg, bv, '-', 'Removed'))
    elif not bv and av:
        changes.append((proj, fw, pkg, '-', av, 'Added'))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]} | {c[5]}')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"

